import { IMessageDataWrapper, IMessageParser } from '@nitrots/nitro-renderer';

export class QuickGuideParser implements IMessageParser {
    private _start: boolean = false;

    public flush(): boolean {
        this._start = false;
        return true;
    }

    public parse(wrapper: IMessageDataWrapper): boolean {
        if (!wrapper) return false;

        // For now we only need a trigger flag
        this._start = wrapper.readBoolean();
        return true;
    }

    public get start(): boolean {
        return this._start;
    }
}
